import{_ as t,o as r,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const b=JSON.parse('{"title":"2.9.1初装","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/2.建卡相关/2.9.初装/2.9.1初装.md","filePath":"1.基础规则/2.建卡相关/2.9.初装/2.9.1初装.md"}'),o={name:"1.基础规则/2.建卡相关/2.9.初装/2.9.1初装.md"};function _(d,a,l,i,c,h){return r(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"_2-9-1初装",tabindex:"-1"},[n("2.9.1初装 "),e("a",{class:"header-anchor",href:"#_2-9-1初装","aria-label":'Permalink to "2.9.1初装"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040威力加强版")])])],-1),s('<h1 id="_2-9-1初装-1" tabindex="-1">2.9.1初装 <a class="header-anchor" href="#_2-9-1初装-1" aria-label="Permalink to &quot;2.9.1初装&quot;">​</a></h1><p>初装</p><p>被过去追在身后是何种感觉？按下确认就可以一劳永逸的摆脱曾经吗？握紧武器，深呼吸，门后是未知的世界，虽然门上不会写着“入此门者，当放弃一切希望”，但你也能透过门缝后吹出的烈风感受到刺骨的寒意。</p><p>初装被分为四档，分别被称为【黎明】、【正午】、【黄昏】、【午夜】，其中一技之长对应【黎明】级初装、二極归中对应【正午】级初装…以此类推至四裔御守对应【午夜】级初装。</p><p>在获得非五星出东的特殊身份时，还可以再从对应档级中挑选一套初装同时获得，若同时拥有多个非五星出东的特殊身份，则按照拥有的特殊身份中最高档级获得初装，在第一场影片结束后，初装的回收价格为每档*10分。若在选择初装时没有任何希望选择的套装，则也可以按照：</p><p>一技之长：初始可以携带一件武器伤害不超过1的武器，例如没有武器伤害的拳套。（若为投掷类则默认一把，以下同理）</p><p>二極归中：初始可以携带一件武器伤害不超过4的现实近战/远程武器。</p><p>三教九流：初始可以携带一件武器价格不超过150分的现实武器；或一件价值不超过50分的现实武器和不超过50分的一件现实盔甲。</p><p>四裔御守：初始可以携带一件价格不超过175分的现实武器和一件价格不超过150分的现实盔甲。</p><p>进行装备携带。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=t(o,[["render",_]]);export{b as __pageData,m as default};
